100:    );
101:    model.setValue(
102:      'BusinessInformation_100_CustomerInfo_WORLD_EN',
103:      customerInfo
104:    );
105:    const currentYear = new Date().getFullYear();
106:    model.setVariable('currentYear', currentYear);
107:
108:    const stateQuestion = model.getQuestionByName(
109:      'BusinessInformation_100_Locations_US_EN'
110:    );
111:    stateQuestion.title = `${stateQuestion.title} ${state}?`;
112:
113:    const stateLocationQuestion = model.getQuestionByName(
114:      'BusinessInformation_100_State_WORLD_EN'
