120:        stateLocationQuestion as QuestionSelectBase
121:      );
122:
123:      model.setValue('BusinessInformation_100_State_WORLD_EN', stateValue);
124:    }
125:
126:    const effectiveDateQuestion = model.getQuestionByName(
