128:    );
129:
130:    if (policyStartDateStr && !effectiveDateQuestion.visible) {
131:      // set effective date
132:      model.setValue(
133:        'BusinessInformation_100_EffectiveDate_WORLD_EN',
134:        policyStartDateStr
135:      );
136:    }
137:
138:    // endorsement case so wcData will not be defined
139:    if (previousAnswers) {
140:      return model;
141:    }
142:
143:    if (!wcData) {
144:      throw new Error('wcData should be defined');
145:    }
146:
147:    switch (wcData.__typename) {
148:      case 'GetJsonWcSuccess': {
149:        model.data = {
150:          ...model.data,
151:          Amtrust_Officers: [
152:            {
153:              name: `${firstName} ${lastName}`
154:            }
155:          ]
156:        };
157:
158:        const { classCodes, rules, isContractor } = wcData;
159:
160:        const amTrustOfficers = getAmtrustOfficerPanel(model);
161:
162:        model.setVariable('rules', rules);
163:        model.setVariable('isContractor', isContractor);
164:        model.setVariable('amtrustAPIFail', false);
165:
166:        if (US.isLongName(state)) {
167:          model.setVariable('UsState', US.getShortName(state));
168:        }
169:
170:        const officerClassCode = amTrustOfficers.template.getQuestionByName(
171:          'duties'
172:        );
173:
174:        if (!(officerClassCode instanceof QuestionMatrixDynamicModel)) {
175:          throw new Error(
176:            'Unreachable - Amtrust_Officers.duties is not based on a question matrix'
177:          );
178:        }
179:
180:        const employeePayroll = model.getQuestionByName(
181:          'Amtrust_EmployeePayrollMatrix_US_EN'
182:        );
183:
184:        if (!(employeePayroll instanceof QuestionMatrixDynamicModel)) {
185:          throw new Error(
186:            'Unreachable - Amtrust_EmployeePayrollMatrix_US_EN is not based on a question matrix'
187:          );
188:        }
189:
190:        const cleanedWcClassCodes = classCodes.map(
191:          ({ id: { __typename, ...id }, description }) => {
192:            void __typename; // strip __typename
193:            return {
194:              text: description,
195:              value: id
196:            };
197:          }
198:        );
199:        officerClassCode.choices = employeePayroll.choices = cleanedWcClassCodes;
200:
201:        break;
202:      }
203:      case 'GetJsonWcError': {
204:        // switch to broker flow
205:
206:        const wcDyanmicQuestionPage = model.getPageByName(
207:          'AmtrustWcAdditionalQuestions'
208:        );
209:
210:        const brokerflowPage = model.getPageByName(
211:          'BrokerWorkersCompensation_0001'
212:        );
213:
214:        wcDyanmicQuestionPage.visible = false;
215:        brokerflowPage.visible = true;
216:
217:        model.setVariable('amtrustAPIFail', true);
218:
219:        break;
220:      }
221:      case 'GetJsonWcUnavailable': {
222:        // don't inject anything
223:        break;
224:      }
225:      default:
226:        throw new Error('Unreachable - unknown wcData response type'); // try updating your GrpahQL schema
227:    }
228:
229:    return model;
230:    // eslint-disable-next-line react-hooks/exhaustive-deps
231:  }, [applicationId, canModelBeSetup]); // note: this dependency array means we can only run this twice per application (i.e. before data is ready and after data is ready)
232:
233:  if (isgetJSONbyApplicationIdLoading) {
234:    return <Loading />;
235:  }
236:
237:  if (getJSONbyApplicationIdError || !getJSONbyApplicationIdData) {
