245:  }
246:
247:  const {
248:    previousAnswers,
249:    policyStartDateStr,
250:    policyExpiryDateStr,
251:    transactionType
252:  } = getJSONbyApplicationIdData.getJSONbyApplicationId;
253:
254:  if (typeof group !== 'string' && group !== undefined) {
255:    throw new Error('Unreachable - group type error');
256:  }
257:
258:  // At this point, model is guaranteed to be a Model instance because:
259:  // - isgetJSONbyApplicationIdLoading is false (line 234 check passed)
260:  // - getJSONbyApplicationIdData is truthy (line 238 check passed)
261:  // - canModelBeSetup was true, so useMemo returned a Model
262:  const readyModel = model as Model;
263:
264:  // for endorsement
265:  if (previousAnswers) {
266:    const {
267:      BusinessInformation_100_EffectiveDate_WORLD_EN,
268:      BusinessInformation_100_Profession_WORLD_EN,
269:      BusinessInformation_100_CustomerInfo_WORLD_EN,
270:      BusinessInformation_100_State_WORLD_EN,
271:      ...previousAnswersWithoutFirstPageAnswers
272:    } = previousAnswers;
273:
274:    // Void the unused variables
275:    void BusinessInformation_100_EffectiveDate_WORLD_EN;
276:    void BusinessInformation_100_Profession_WORLD_EN;
277:    void BusinessInformation_100_CustomerInfo_WORLD_EN;
278:    void BusinessInformation_100_State_WORLD_EN;
279:
280:    // TODO find a better way to set this flag
281:    readyModel.setVariable('isEndorsement', true);
282:
283:    readyModel.setDataCore({
284:      ...readyModel.data,
285:      ...previousAnswersWithoutFirstPageAnswers
286:    });
287:  }
288:
289:  setMinMaxDateForEffectiveDate(
290:    readyModel,
291:    policyStartDateStr,
292:    policyExpiryDateStr,
293:    transactionType
294:  );
295:
296:  // for endorsement
297:  if (previousAnswers) {
298:    readyModel.runTriggers();
299:  }
300:
301:  interface AddressParams {
302:    country: string;
303:    province: string;
304:    brokerCode?: string;
305:  }
306:  const { country, province, brokerCode } = location.state as AddressParams;
307:  const urlData = location.state as UnderwritingUrlData;
308:  return (
309:    <div className="h-full Commercial" data-testid="Commercial">
310:      <CommercialSurveyWithApplicationId
311:        model={readyModel}
312:        applicationId={applicationId}
313:        groupName={group}
314:        country={country}
315:        province={province}
316:        urlData={urlData}
317:        brokerCode={brokerCode}
318:      />
319:    </div>
320:  );
321:};
322:
323:export default CommercialWithApplicationId;
