test('should correctly strip __typename from classCodes and map to text/value', () => {
  // Verifies classCodes are cleaned: __typename removed, mapped to {text, value} format
  const mockOfficerClassCode = new QuestionMatrixDynamicModel('duties');
  const mockEmployeePayroll = new QuestionMatrixDynamicModel(
    'Amtrust_EmployeePayrollMatrix_US_EN'
  );

  (getAmtrustOfficerPanel as jest.Mock).mockReturnValue({
    template: {
      getQuestionByName: jest.fn(() => mockOfficerClassCode)
    }
  });

  jest
    .spyOn(Model.prototype, 'getQuestionByName')
    .mockImplementation((name) => {
      if (name === 'BusinessInformation_100_EffectiveDate_WORLD_EN') {
        return { visible: false } as any;
      }
      if (name === 'Amtrust_EmployeePayrollMatrix_US_EN') {
        return mockEmployeePayroll as any;
      }
      return { title: 'Test Question', visible: true, choices: [] } as any;
    });

  const dataWithMultipleClassCodes = {
    ...mockQueryData,
    getJSONbyApplicationId: {
      ...mockQueryData.getJSONbyApplicationId,
      wcData: {
        __typename: 'GetJsonWcSuccess',
        classCodes: [
          {
            id: { __typename: 'ClassCodeId', code: '8810', state: 'CA' },
            description: 'Clerical Office Employees'
          },
          {
            id: { __typename: 'ClassCodeId', code: '5190', state: 'NY' },
            description: 'Electrical Wiring'
          }
        ],
        rules: [{ ruleId: 'r1' }],
        isContractor: true
      }
    }
  };

  (useGetJsoNbyApplicationIdQuery as jest.Mock).mockReturnValue({
    loading: false,
    error: null,
    data: dataWithMultipleClassCodes
  });

  renderWithRouter(mockLocationState);

  const expectedChoices = [
    {
      text: 'Clerical Office Employees',
      value: { code: '8810', state: 'CA' }
    },
    { text: 'Electrical Wiring', value: { code: '5190', state: 'NY' } }
  ];

  expect(mockOfficerClassCode.choices).toEqual(expectedChoices);
  expect(mockEmployeePayroll.choices).toEqual(expectedChoices);
});

